<?php
 namespace WPAICG\Utils; use WPAICG\Chat\Storage\BotStorage; if (!defined('ABSPATH')) { exit; } class AIPKit_CORS_Manager { private static $cors_enabled_actions = [ 'aipkit_get_frontend_chat_nonce', 'aipkit_get_conversations_list', 'aipkit_get_conversation_history', 'aipkit_store_feedback', 'aipkit_generate_speech', 'aipkit_transcribe_audio', 'aipkit_delete_single_conversation', 'aipkit_cache_sse_message', 'aipkit_frontend_chat_stream', 'aipkit_chat_generate_image', ]; public static function init(): void { if (!self::is_embed_feature_available()) { return; } add_action('admin_init', [self::class, 'handle_ajax_cors']); } private static function is_embed_feature_available(): bool { if (!class_exists('\WPAICG\aipkit_dashboard')) { return false; } return \WPAICG\aipkit_dashboard::is_pro_plan(); } public static function handle_ajax_cors(): void { if (!wp_doing_ajax()) { return; } if (!self::is_embed_feature_available()) { return; } $action = isset($_REQUEST['action']) ? sanitize_text_field(wp_unslash($_REQUEST['action'])) : ''; if (!in_array($action, self::$cors_enabled_actions, true)) { return; } self::handle_preflight_request(); $bot_id = 0; if (isset($_POST['bot_id'])) { $bot_id = absint(wp_unslash($_POST['bot_id'])); } elseif (isset($_GET['bot_id'])) { $bot_id = absint(wp_unslash($_GET['bot_id'])); } if ($bot_id > 0) { $origin_allowed = self::check_and_set_cors_headers($bot_id); if (!$origin_allowed) { self::set_cors_headers('null'); } } else { self::set_cors_headers(); } } public static function check_and_set_cors_headers(int $bot_id, ?BotStorage $bot_storage = null): bool { $request_origin = null; if (isset($_SERVER['HTTP_ORIGIN'])) { $request_origin = esc_url_raw(wp_unslash($_SERVER['HTTP_ORIGIN'])); } if (empty($request_origin)) { return true; } $is_cross_origin = false; $site_url = get_site_url(); $site_parsed = wp_parse_url($site_url); $origin_parsed = wp_parse_url($request_origin); if ($origin_parsed && $site_parsed && ($origin_parsed['host'] !== $site_parsed['host'] || ($origin_parsed['scheme'] ?? 'http') !== ($site_parsed['scheme'] ?? 'http'))) { $is_cross_origin = true; } if (!$is_cross_origin) { return true; } if (!self::is_embed_feature_available()) { return false; } if (!$bot_storage) { $bot_storage = new BotStorage(); } $bot_settings = $bot_storage->get_chatbot_settings($bot_id); if (empty($bot_settings)) { return false; } $allowed_domains_str = $bot_settings['embed_allowed_domains'] ?? ''; $allowed_domains = preg_split('/[\s,]+/', $allowed_domains_str, -1, PREG_SPLIT_NO_EMPTY); $origin_is_allowed = false; $origin_to_allow = '*'; if (empty($allowed_domains)) { $origin_is_allowed = true; $origin_to_allow = $request_origin; } else { $normalized_request_origin = rtrim($request_origin, '/'); foreach ($allowed_domains as $allowed_domain) { $normalized_allowed_domain = rtrim($allowed_domain, '/'); if ($normalized_request_origin === $normalized_allowed_domain) { $origin_is_allowed = true; $origin_to_allow = $request_origin; break; } } } if ($origin_is_allowed) { self::set_cors_headers($origin_to_allow); } return $origin_is_allowed; } public static function set_cors_headers(string $allowed_origin = '*'): void { header('Access-Control-Allow-Origin: ' . $allowed_origin); header('Access-Control-Allow-Methods: POST, GET, OPTIONS'); header('Access-Control-Allow-Headers: Content-Type, X-Requested-With, Authorization'); header('Access-Control-Allow-Credentials: true'); } public static function handle_preflight_request(): void { $request_method = isset($_SERVER['REQUEST_METHOD']) ? strtoupper(sanitize_text_field(wp_unslash((string) $_SERVER['REQUEST_METHOD']))) : ''; if ($request_method === 'OPTIONS') { self::set_cors_headers(); status_header(200); exit; } } } 